// Define the structure for a tree node
struct Node {
    int value;
    vector<Node*> children;
};
// Function to create a new tree node
Node* createNode(int value) {
    Node* node = new Node;
    node->value = value;
    return node;
}
// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->children.push_back(child);
}
// Function to calculate the maximum product of three paths
int maxProduct(Node* node) {
    // Base case: if the node is a leaf, return 0
    if (node->children.empty()) return 0;
    // Initialize the maximum product
    int maxProd = 0;
    // Iterate over all possible combinations of three paths
    for (int i = 0; i < node->children.size(); i++) {
        for (int j = i + 1; j < node->children.size(); j++) {
            for (int k = j + 1; k < node->children.size(); k++) {
                // Calculate the product of the lengths of the three paths
                int prod = (node->children[i]->value) * (node->children[j]->value) * (node->children[k]->value);
                // Update the maximum product
                if (prod > maxProd) maxProd = prod;
            }
        }
    }
    return maxProd;
}
int main() {
    int n;
    cin >> n;
    // Create the tree nodes
    Node** nodes = new Node*[n];
    for (int i = 0; i < n; i++) nodes[i] = createNode(i + 1);
    // Read the edges and add the children
    for (int i = 0; i < n - 1; i++) {
        int u, v;
        cin >> u >> v;
        addChild(nodes[u - 1], nodes[v - 1]);
    }
    // Calculate and print the maximum product
    cout << maxProduct(nodes[0]) << endl;
    return 0;
}

