import java.util.ArrayList;
import java.util.Scanner;
public class Main {
    static class Node {
        int value;
        ArrayList<Node> children;
        public Node(int value) {
            this.value = value;
            this.children = new ArrayList<>();
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        Node[] nodes = new Node[n];
        for (int i = 0; i < n; i++) {
            nodes[i] = new Node(i + 1);
        }
        for (int i = 0; i < n - 1; i++) {
            int u = scanner.nextInt() - 1;
            int v = scanner.nextInt() - 1;
            nodes[u].children.add(nodes[v]);
        }
        System.out.println(maxProduct(nodes[0]));
    }
    public static int maxProduct(Node node) {
        if (node.children.isEmpty()) return 0;
        int maxProd = 0;
        for (int i = 0; i < node.children.size(); i++) {
            for (int j = i + 1; j < node.children.size(); j++) {
                for (int k = j + 1; k < node.children.size(); k++) {
                    int prod = node.children.get(i).value * node.children.get(j).value * node.children.get(k).value;
                    if (prod > maxProd) maxProd = prod;
                }
            }
        }
        return maxProd;
    }
}

