function maxProduct(node) {
    if (node.children.length === 0) return 0;
    let maxProd = 0;
    for (let i = 0; i < node.children.length; i++) {
        for (let j = i + 1; j < node.children.length; j++) {
            for (let k = j + 1; k < node.children.length; k++) {
                let prod = node.children[i].value * node.children[j].value * node.children[k].value;
                if (prod > maxProd) maxProd = prod;
            }
        }
    }
    return maxProd;
}
function main() {
    const readline = require('readline');
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });
    let n;
    let nodes;
    rl.on('line', (input) => {
        if (!n) {
            n = parseInt(input);
            nodes = Array(n).fill(0).map((_, i) => new Node(i + 1));
        } else {
            const [u, v] = input.split(' ').map((x) => parseInt(x));
            nodes[u - 1].children.push(nodes[v - 1]);
            if (nodes[u - 1].children.length === n - 1) {
                console.log(maxProduct(nodes[0]));
                rl.close();
            }
        }
    });
